(521,7,1,'SINGLE','EASY','已知森林 F 及与之对应的二叉树 T，若 F 的先根遍历序列是 a, b, c, d, e, f，中根遍 历序列是 b, a, d, f, e, c 则 T 的后根遍历序列是：','[{"key": "A", "value": "b, a, d, f, e, c"}, {"key": "B", "value": "b, d, f, e, c, a"}, {"key": "C", "value": "b, f, e, d, c, a"}, {"key": "D", "value": "f, e, d, c, b, a"}]','D','2020年408真题第4题',2020),
